import{_ as r,o as t,c as n,j as e,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"石中剑","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/2.武器/近战武器/1.D级/石中剑.md","filePath":"4.资源分区/7.物品与装备/2.武器/近战武器/1.D级/石中剑.md"}'),d={name:"4.资源分区/7.物品与装备/2.武器/近战武器/1.D级/石中剑.md"};function l(p,a,_,i,b,c){return t(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"石中剑",tabindex:"-1"},[s("石中剑 "),e("a",{class:"header-anchor",href:"#石中剑","aria-label":'Permalink to "石中剑"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：灵魂蓝调015")])])],-1),o('<h1 id="石中剑-1" tabindex="-1">石中剑 <a class="header-anchor" href="#石中剑-1" aria-label="Permalink to &quot;石中剑&quot;">​</a></h1><p>石中剑<br> D+1000<br> 科技本质<br> 传说，石中剑第一次出现时是圣诞节前夜，当人们忏悔完毕抬起头时，便看到一柄奇异的宝剑插在一块四方的石头上。无数人对其感到好奇，就连大主教都派一位骑士前来调查，无数人试图将其拔出，毫无意外地全都失败了。这下传闻流传更广，人们都说：拔出石中剑者当为王。<br> 当然，传闻只是传闻罢了，一个化名为亚瑟的轮回者成功将那个世界的石中剑带了回来，原来，这是一块穿越到异世界的钢筋混凝土。<br> 这是一块由两根螺旋钢作为主体，以复杂且精湛的浇灌技术筑成的混凝土方块，其重量令人颇为汗颜，硬度也足以让敌人瞠目结舌，它毫无战斗美感，能够挥动的人无非就是肌肉大猩猩吧。<br> “如果真能徒手把钢筋从混凝土里拔出来那确实没人能拦得住你称王”——轮回者·亚瑟</p><p>武器类别：锤<br> 专业：武技-锤<br> 前置条件：力量5+<br> 武器伤害：7L<br> 体积：4<br> 特性：【重型武器】【双手】【威猛5】<br> 【现代土木工程之力】：这把武器的硬度为10，由于某种神秘的唯物主义现代科学力量，这把武器具有【法破】；由于挥动一块钢筋混凝土砸人的画面表现太过震撼，在攻击时具有2dp表现加值。</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',5)])])}const m=r(d,[["render",l]]);export{f as __pageData,m as default};
